+
+/* Starlight Tabs Component Styling - Per Tenzir Tab Bar Design System */
+starlight-tabs {
+  display: block;
+  margin: var(--tnz-space-6) 0;
+}
+
+/* Tab list container - 48px height */
+starlight-tabs [role="tablist"] {
+  display: flex;
+  align-items: center;
+  gap: var(--tnz-space-2); /* 8px - slightly more than spec for readability */
+  height: 48px;
+  border-bottom: none;
+  margin-bottom: var(--tnz-space-4);
+  overflow-x: auto;
+  scrollbar-width: none;
+}
+
+starlight-tabs [role="tablist"]::-webkit-scrollbar {
+  display: none;
+}
+
+/* Individual tab - 48px height */
+starlight-tabs [role="tab"] {
+  position: relative;
+  display: flex;
+  align-items: center;
+  height: 48px;
+  padding: 0;
+  padding-bottom: 2px; /* Space for indicator */
+  background-color: transparent;
+  border: none;
+  cursor: pointer;
+  text-decoration: none !important;
+}
+
+/* Tab text container - 6px/8px padding, 5px radius for hover bg */
+starlight-tabs [role="tab"] > * {
+  display: flex;
+  align-items: center;
+  gap: var(--tnz-space-1); /* 4px */
+  padding: var(--tnz-space-1-5) var(--tnz-space-2); /* 6px 8px */
+  border-radius: var(--tnz-radius); /* 5px */
+  font-size: var(--tnz-text-sm); /* 14px */
+  font-weight: var(--tnz-font-medium); /* 500 */
+  line-height: var(--tnz-leading-sm); /* 20px */
+  white-space: nowrap;
+  transition: background-color var(--tnz-transition-base), color var(--tnz-transition-base);
+}
+
+/* Inactive state - neutral-500 text */
+starlight-tabs [role="tab"] {
+  color: var(--tnz-neutral-400);
+}
+
+/* Tab bottom border indicator - 2px */
+starlight-tabs [role="tab"]::after {
+  content: '';
+  position: absolute;
+  bottom: 0;
+  left: 0;
+  right: 0;
+  height: 2px;
+  background-color: transparent;
+  transition: background-color var(--tnz-transition-base);
+}
+
+/* Hover state - background on text container */
+starlight-tabs [role="tab"]:hover {
+  color: var(--tnz-neutral-200);
+}
+
+starlight-tabs [role="tab"]:hover > * {
+  background-color: var(--tnz-neutral-700);
+}
+
+/* Focus state */
+starlight-tabs [role="tab"]:focus-visible {
+  outline: none;
+}
+
+starlight-tabs [role="tab"]:focus-visible > * {
+  outline: 2px solid var(--tnz-primary-500);
+  outline-offset: 2px;
+}
+
+/* Active state - primary color text, 2px bottom border */
+starlight-tabs [role="tab"][aria-selected="true"] {
+  color: var(--tnz-primary-400);
+}
+
+starlight-tabs [role="tab"][aria-selected="true"]::after {
+  background-color: var(--tnz-primary-500);
+}
+
+/* Active overrides hover */
+starlight-tabs [role="tab"][aria-selected="true"]:hover > * {
+  background-color: transparent;
+}
+
+starlight-tabs [role="tab"][aria-selected="true"]:hover {
+  color: var(--tnz-primary-400);
+}
+
+/* Tab icon styling */
+starlight-tabs [role="tab"] svg {
+  width: 16px;
+  height: 16px;
+  flex-shrink: 0;
+}
+
+/* Tab panel styling */
+starlight-tabs [role="tabpanel"] {
+  padding: 0;
+}
+
+/* Light mode - use design system light mode colors */
+:root[data-theme="light"] starlight-tabs [role="tab"] {
+  color: var(--tnz-neutral-500);
+}
+
+:root[data-theme="light"] starlight-tabs [role="tab"]:hover {
+  color: var(--tnz-neutral-700);
+}
+
+:root[data-theme="light"] starlight-tabs [role="tab"]:hover > * {
+  background-color: var(--tnz-neutral-100);
+}
+
+:root[data-theme="light"] starlight-tabs [role="tab"][aria-selected="true"] {
+  color: var(--tnz-neutral-800);
+}
+
+:root[data-theme="light"] starlight-tabs [role="tab"][aria-selected="true"]:hover {
+  color: var(--tnz-neutral-800);
+}
+
+:root[data-theme="light"] starlight-tabs [role="tab"][aria-selected="true"]:hover > * {
+  background-color: transparent;
+}
+
+/* Reduced motion support */
+@media (prefers-reduced-motion: reduce) {
+  starlight-tabs [role="tab"] > *,
+  starlight-tabs [role="tab"]::after {
+    transition: none;
+  }
+}
